sql:
SELECT total_charges, insurance_coverage 
FROM billing 
WHERE billing_id = 1;

SELECT admission_id, patient_id, facility_id, admission_date, type_of_admission, discharge_status
FROM admissions
WHERE admission_id = 1;

external_knowledge:
- 'Transferred' refers to patients who were moved from one healthcare facility to another for further treatment or care; 
- 'Hospital' is a type of healthcare facility providing advanced medical care for complex cases;
- The number '10000' refers to the US dollar amount of ten thousand, representing the threshold for total charges; 
- The 'most recent hospital visit' or 'most recent admission' signifies the latest instance when a patient was admitted to a hospital for treatment or care.

sql:
SELECT facility_name, bed_count
FROM healthcare_facilities
WHERE bed_count > (SELECT AVG(bed_count) FROM healthcare_facilities);

SELECT transfer_reason, transfer_facility_id
FROM transfer_details
WHERE transfer_reason = 'Medical';

SELECT COUNT(abortion_edit_indicator_id) AS count_of_admissions
FROM abortion_edit_indicators
WHERE abortion_edit_indicator = 'N' AND admission_id = 1;

external_knowledge:
- Primary provider refers to the attending provider with the highest rank; 
- Discharge status of 'Discharged' or 'Transferred' implies that the patient's hospital stay has ended;
- A length of stay of more than 0 days indicates that the patient was hospitalized for at least one day.

sql:
SELECT AVG(birth_weight) AS average_birth_weight
FROM birth_weights
WHERE gestational_age = 38;

SELECT admission_id
FROM emergency_department_indicators
WHERE emergency_department_indicator = 'N';
